import { AWSDataSourceJsonData, AWSDataSourceSettings, AWSDataSourceType, CreateDataSourceParams } from 'types/types';
import { createDataSource, buildARN, serviceToDSMap, shouldSetAssumeRole } from './datasource';

export interface TimeStreamJsonData extends AWSDataSourceJsonData {
  assumeRoleArn?: string;
}

export type TimeStreamDataSourceSettings = AWSDataSourceSettings<TimeStreamJsonData>;

export function createTimeStreamDataSource(
  params: CreateDataSourceParams,
  installedDSNames: Set<string>,
  workspaceAccountId: string
) {
  let dsSettings: TimeStreamDataSourceSettings = {
    jsonData: {
      authType: 'ec2_iam_role',
      defaultRegion: params.region,
    },
  };

  let dsName = `${serviceToDSMap.timestream.name} ${params.region}`;

  if (params.account) {
    dsName = `${dsName} ${params.account.id}`;
  }

  if (params.account && params.roleName && dsSettings.jsonData && shouldSetAssumeRole(params, workspaceAccountId)) {
    dsSettings.jsonData.assumeRoleArn = buildARN(params.account.id, params.roleName);
  }

  return createDataSource(AWSDataSourceType.TimeStream, dsName, dsSettings, installedDSNames);
}
