import React, { useMemo, useEffect } from 'react';
import { AppRootProps, IconName } from '@grafana/data';
import { Services } from '../Services';
import { DataSources } from '../DataSources';
import { Settings } from '../Settings';
import { findActiveTab, getNavModel } from '../../utils';
import { DataProvider } from '../App/DataProvider';
import { ServiceInfo } from '../../types/types';

export type Tab = {
  id: string;
  label: string;
  icon: IconName;
  enabledByFeatureFlag?: string;
  component: React.JSXElementConstructor<any>;
};

export interface TabComponentProps {
  services: ServiceInfo[];
}

export const tabs: Tab[] = [
  {
    id: 'services',
    label: 'AWS services',
    icon: 'cube',
    component: Services,
  },
  {
    id: 'datasources',
    label: 'Data sources',
    icon: 'database',
    component: DataSources,
  },
  {
    id: 'settings',
    label: 'Settings',
    icon: 'sliders-v-alt',
    component: Settings,
  },
];

export const Tabs = ({ query, onNavChanged, path, meta }: AppRootProps) => {
  const selectedTabId = query.tab;
  const activeTab = useMemo(() => findActiveTab(tabs, selectedTabId), [selectedTabId]);
  const logoUrl = meta.info.logos.large;

  useEffect(() => {
    onNavChanged(getNavModel(tabs, path, activeTab, logoUrl));
  }, [activeTab, path, onNavChanged, logoUrl]);

  const Component = activeTab?.component;
  return (
    <DataProvider>
      <Component query={query} meta={meta} />
    </DataProvider>
  );
};
